PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT DISTINCT ?celebrity ?celebrityLabel WHERE {
  VALUES ?sister {
    wd:Q520008 wd:Q1014815 wd:Q1929550
  }
  ?sister wdt:P26 ?celebrity .
  ?celebrity rdfs:label ?celebrityLabel .
  FILTER(LANG(?celebrityLabel) = 'en')
}
